#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAX_N 100005
#define MAX_Q 1500005

// Define the structure for a tree node
typedef struct Node {
    int value;
    struct Node* parent;
    struct Node** children;
    int numChildren;
} Node;

// Function to create a new node
Node* createNode(int value) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->value = value;
    node->parent = NULL;
    node->children = NULL;
    node->numChildren = 0;
    return node;
}

// Function to update the value of a node and its ancestors and descendants
void updateNode(Node* node, int y) {
    node->value = (node->value + (1 << y)) % MOD;
    if (node->parent != NULL) {
        updateNode(node->parent, y - 1);
    }
    for (int i = 0; i < node->numChildren; i++) {
        updateNode(node->children[i], y - 1);
    }
}

// Function to query the value of a node
int queryNode(Node* node) {
    return node->value;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        Node** nodes = (Node**)malloc(N * sizeof(Node*));
        for (int i = 0; i < N; i++) {
            nodes[i] = createNode(0);
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--;
            v--;
            nodes[u]->children = (Node**)realloc(nodes[u]->children, (nodes[u]->numChildren + 1) * sizeof(Node*));
            nodes[u]->children[nodes[u]->numChildren] = nodes[v];
            nodes[u]->numChildren++;
            nodes[v]->parent = nodes[u];
        }
        for (int i = 0; i < Q; i++) {
            int type, x, y;
            scanf("%d %d", &type, &x);
            x--;
            if (type == 1) {
                scanf("%d", &y);
                updateNode(nodes[x], y);
            } else {
                printf("%d\n", queryNode(nodes[x]));
            }
        }
        for (int i = 0; i < N; i++) {
            free(nodes[i]->children);
            free(nodes[i]);
        }
        free(nodes);
    }
    return 0;
}

